const trigger = $('Set: Store Trigger Data').first().json;

// --- Extract LinkedIn DM ---
const dmRaw = $('LLM: LinkedIn DM').first().json.text || '';
const linkedin_dm = dmRaw.trim();

// --- Extract LinkedIn Post ---
const postRaw = $('LLM: LinkedIn Post').first().json.text || '';
const postCleaned = postRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let linkedin_post = { hook: '', absaetze: [], community_frage: '' };
try {
  linkedin_post = JSON.parse(postCleaned);
} catch (e) {
  linkedin_post = {
    hook: postRaw.substring(0, 200) || 'Post-Idee konnte nicht geparst werden',
    absaetze: [],
    community_frage: 'Was sind eure Erfahrungen damit?'
  };
}

// --- Build combined storage value for column V ---
const linkedin_nachricht_value = JSON.stringify({
  dm: linkedin_dm,
  post: linkedin_post
});

// --- Build WF6 inputs ---
const updates = JSON.stringify({
  linkedin_nachricht: linkedin_nachricht_value
});

const log_eintrag = JSON.stringify({
  aktion: 'linkedin_content_generiert',
  inhalt: 'DM + Post-Idee erstellt',
  status: 'ok'
});

return [{
  json: {
    lead_id: trigger.lead_id,
    updates: updates,
    log_eintrag: log_eintrag,
    _linkedin_dm: linkedin_dm,
    _linkedin_post: linkedin_post
  }
}];
